window.__QUIZ_DATA__=[{"id":"theory>Chemistry>1993>1>a","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES","question":"Classify each of the following as physical change or a chemical change:    fractional distillation of liquefied air;","images":[],"marking_scheme":"Physical change","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>1>b","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.","question":"Classify each of the following as physical change or a chemical change:  cracking of petroleum fractions;","images":[],"marking_scheme":"Chemical change","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>1>c","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"c","group":"","topic":"STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES","question":"Classify each of the following as physical change or a chemical change:  conversion of rhombic sulphur to monoclinic sulphur;","images":[],"marking_scheme":"Physical change","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>1>d","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"d","group":"","topic":"STATES OF MATTER : KINETIC THEORY OF MATTER.","question":"Classify each of the following as physical change or a chemical change:  chromatographic separation of chlorophyll.","images":[],"marking_scheme":"Physical change","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>2>a>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"WATER","question":"Give one disadvantage of:   hard water","images":[],"marking_scheme":"-It wastes soap  -It causes furring of kettles and boilers","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>2>a>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"WATER","question":"Give one disadvantage of:  soft water","images":[],"marking_scheme":"-Soft water lacks calcium and such water can ease tooth decay.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>1993>2>b","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"WATER","question":"Explain why the degree of hardness in a sample of clear lime water is higher than in another sample has that been turned milky by carbon (IV) oxide.","images":[],"marking_scheme":"Clear lime water contains high content of soluble calcium which can precipitate soap in a higher degree than the sample of lime water already turned milky by carbon(IV) oxide. The milkiness is caused by the presence of insoluble calcium trioxocarbonate (IV)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>3>a>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"State one air pollution that causes:    blood poisoning","images":[],"marking_scheme":"Carbon(II) oxide prevents the oxygenation of the blood.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>1993>3>a>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"State one air pollution that causes:  acid poisoning","images":[],"marking_scheme":"Sulphur(IV) oxide resolved in rain water ged in rain water in the atmosphere to give acid rain.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>3>a>iii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"iii","group":"","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"State one air pollution that causes:  blackening of the walls of buildings","images":[],"marking_scheme":"Hydrogen sulphide reacts with the lead content of the paint to give black stains of lead(II) sulphide","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>3>b>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"Mention one major chemical industry in each case which requires the following as raw materials:  peetrochemicals","images":[],"marking_scheme":"Petrochemical industry","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>3>b>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"Mention one major chemical industry in each case which requires the following as raw materials:   cellulose","images":[],"marking_scheme":"Brewery or Brewing industry.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>4>a>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"STATES OF MATTER : THE GAS LAWS","question":"If L is the Avogadro constant and E\u00b0 is standard cell potential, state what X and Y stand for in the following expressions    X = Mass of L molecules of gas or vapour / Mass of L molecules of hydrogen","images":[],"marking_scheme":"X = Vapour density of a gas","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>4>a>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"REDOX REACTIONS : ELECTROCHEMICAL CELLS","question":"If L is the Avogadro constant and E\u00b0 is standard cell potential, state what X and Y stand for in the following expressions  Y = -nFE\u00b0","images":[],"marking_scheme":"Y = Free energy of change (\u0394   G)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>4>b","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"REDOX REACTIONS : ELECTROCHEMICAL CELLS","question":"State two differences between a primary cell and a secondary cell.","images":[],"marking_scheme":"Primary cell cannot be recharged after it has used up the chemicals of which it is composed. The secondary cell can be charged. In the primary cell, the cathode is a zinc rod and the electrolyte in which they are s ammonium chloride solution. In the secondary cell, the cathode and the anode are both grids of lead-antimony alloy immersed in diluted H2SO4 solution.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>5>a>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"NON METALS AND THEIR COMPOUNDS : HYDROGEN SULPHIDE","question":"State the phenomenon illustrated by the:  spreading of the smell of hydrogen sulphide gas in the laboratory;","images":[],"marking_scheme":"The spreading of a smell is called diffusion which is simply the movement of parbcies of a substance from region of higher concentration to that of lower concentration.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>1993>5>a>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE ATOM : ISOTOPES","question":"State the phenomenon illustrated by the:  existence of atoms of the same element having different mass numbers","images":[],"marking_scheme":"Isotopy","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>5>b","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"STRUCTURE OF THE ATOM : ISOTOPES","question":"The atomic number of an element is 17. It has different atoms containing 18 neutrons and 20 neutrons, with a relative abundance of 75% and 25% respectively. Calculate the relative atomic mass of the element.","images":[],"marking_scheme":"The relative atomic mass = 17 + 18 = 35, 17 + 20 = 37  =(35 x 75/100) + (37 xx 25/100)  =(35 x 0.75) + (37 x 0.25)  = 26.25 + 9.25   = 35.5","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>1993>6>a>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.","question":"Name the residue obtained on strongly heating the following:  ZnCO3 in an open crucible;","images":[],"marking_scheme":"Yellow zinc (II) oxide is the residue when Zinc (II) trioxocarbonate (IV) is strongly heated in an open crucible.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>6>a>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.","question":"Name the residue obtained on strongly heating the following:  CuSO4.5H2O and then allowing it to cool in a desiccator.","images":[],"marking_scheme":"White powdery mass of anhydrous copper(II) tetraoxosulphate (VI) is left as the residue in the desiccator","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>6>b","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"ACIDS, BASES AND SALTS : DELIQUESCENT, EFFLORESCENT AND HYGROSCOPIC COMPOUND.","question":"State the colour changes observed on heating and cooling in each case in(a) above.","images":[],"marking_scheme":"(a)(i) above when hot, it is yellow and white when cold.    (ii) above, when hot, it is white and blue when cold","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>1993>7>a","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"STATES OF MATTER : DIAMOND AND GRAPHITE","question":"Mention the respective properties of the following allotropes of carbon that account for their uses as indicated:    diamond used for drilling rocks;","images":[],"marking_scheme":"The hardness of diamond.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>7>b","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"STATES OF MATTER : DIAMOND AND GRAPHITE","question":"Mention the respective properties of the following allotropes of carbon that account for their uses as indicated:  diamond used as jewels;","images":[],"marking_scheme":"The characteristic lustre of diamond","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>7>c","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"c","group":"","topic":"STATES OF MATTER : DIAMOND AND GRAPHITE","question":"Mention the respective properties of the following allotropes of carbon that account for their uses as indicated:  graphite used as electrodes;","images":[],"marking_scheme":"The electrical conductivity of graphite","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>7>d","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"d","group":"","topic":"STATES OF MATTER : DIAMOND AND GRAPHITE","question":"Mention the respective properties of the following allotropes of carbon that account for their uses as indicated:  graphite used for slowing down neutrons in nuclear reactors;","images":[],"marking_scheme":"Soft nature of graphite","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>7>e","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"e","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS","question":"Mention the respective properties of the following allotropes of carbon that account for their uses as indicated:  wood charcoal used in gas masks.","images":[],"marking_scheme":"The porous nature of wood charcoal makes it good absorbent for gases.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>8","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"8","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS","question":"State which of the following can exhibit geometric isomerism:     Give reason for your answer","images":["data:image/png;base64,"],"marking_scheme":"(a) and (d) can exhibit geometric isomerism because of the restriction to movement of the molecule about the double bond.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>9>a>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"PERIODIC CHEMISTRY : REACTIONS BETWEEN ACIDS AND METALS, THEIR OXIDES AND TRIOXOCARBONATES (IV).","question":"X and Y belong to the same period in the Periodic Table is a group I element while Y belongs to group VII. State which of the elements would    be a good oxidizing agent","images":[],"marking_scheme":"Element Y","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>9>a>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS","question":"X and Y belong to the same period in the Periodic Table is a group I element while Y belongs to group VII. State which of the elements would  have the smaller atomic volume","images":[],"marking_scheme":"Element Y","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>9>a>iii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"iii","group":"","topic":"PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS","question":"X and Y belong to the same period in the Periodic Table is a group I element while Y belongs to group VII. State which of the elements would  have the higher ionization potential","images":[],"marking_scheme":"Element Y","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>9>b","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"Explain your answer in (a)(i) above.","images":[],"marking_scheme":"he element Y is in group VII and so it has a smaller atomic volume than element X which is in group    I. This size of the atom is a measure of the atomic radius. The smaller the atom is, the more is the attractive force between the outermost electron and the nucleus and this is the reason why element Y will be a better acceptor of electron than X as oxidizing agent.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>1993>10>a","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS","question":"The compound whose formula is written below is a major component of a soft fatty substance:     State the change that would be observed in the physical state of the fatty substance if hydrogen were bubbled through it for long time in the presence of finely divided nickel at about 180oC","images":["data:image/png;base64,"],"marking_scheme":"It will be hardened","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>10>b","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Determine the amount (in mole) of hydrogen that would be consumed if one mole of the component reacted completely with hydrogen.","images":[],"marking_scheme":"3 moles of hydrogen molecules","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>10>c","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"c","group":"","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS","question":"State the product of the reaction of the fatty substance with hot concentrated sodium hydroxide solution","images":[],"marking_scheme":"Sodium salt of a fatty acid which is soap.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>11>a>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Distinguish between a strong acid and a concentrated acid.","images":[],"marking_scheme":"Strong acid can ionize completely   E.g. HCI(aq) \u2192 H+(aq) + CI\u2212(aq)  Concentrated acid means great amount of the acidic compound dissolved in little amount of water.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>11>a>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"What is meant by amphoteric oxide? Give one example.","images":[],"marking_scheme":"Amphoteric oxide is a metallic oxide which is both acidic and basic.   E.g Al2O3 + 6HCl \u2192 2AICl3 + 3H2O(l)    Al2O3(s) + 2NaO(aq) + 3H2  O(l) \u2192 2NaAl(OH)4(aq)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>11>b>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Describe the manufacture of tetraoxosulphate (VI) acid by contact process.","images":["data:image/png;base64,"],"marking_scheme":"The manufacture of H2SO4 by contact process sulphur(VI) oxide, the anhydride of H2SO4 can be obtained by contact process which entails     The sulphur(VI) To dissolved in concentrated H2SO4 to form, a fuming liquid called oleum (H2S2  O7(aq)  H2SO4(aq) + SO3(g) \u2192 (H2S2O7(aq)    The oleum is carefully diluted with correct amount of water to .give ordinary concentrated    H2SO4.H2S2O7(aq) + H2O(l) \u2192 2H2SO4(aq)","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>1993>11>b>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"ACIDS, BASES AND SALTS : ACID-BASE REACTIONS","question":"Write one equation each to show the action of tetraoxosulphate (VI) acid respectively as a dehydrating agent and as an oxidizing agent.","images":[],"marking_scheme":"H2SO4 as an oxidizing agent C(S) + 2H2SO4(aq) \u2192 2H2O(l) + 2SO2(g) + CO2(s)  H2SO4 as a dehydration agent H2C2O4(g) + H2SO4(l) \u2192 CO(g) + CO2(g) + (H2O + H2SO4(aq)","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>1993>11>b>iii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"iii","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Give the reason why tetraoxosulphate(VI) acid is classified as a heavy chemical.","images":[],"marking_scheme":"It is commonly used in most industries.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>12>a>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS","question":"Define the term polymerization.","images":[],"marking_scheme":"Polymerization is the combination of many molecules of the same kind to form a complex molecule Conc. H2SO4 without gain or loss of material.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>1993>12>a>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS","question":"List the three conditions required for the polymerization of ethene.","images":[],"marking_scheme":"-High temperature of about 250oC  -High pressure above 1500atm  -traces of oxygen as an initiator","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>12>a>iii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"iii","group":"","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS","question":"State the property which is common to compounds that can be easily polymerized","images":[],"marking_scheme":"Consist of double or triple bond (unsaturation) and repeating unit.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>1993>12>b>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKENES","question":"Write appropriate equations to show how the following can be obtained from propan-1-ol in the labouratory:  propene;","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>1993>12>b>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS","question":"Write appropriate equations to show how the following can be obtained from propan-1-ol in the labouratory:  propylmethanoate. State the type of reaction involved in each case.","images":[],"marking_scheme":"CH3CH2CH2OH(aq)  + CHOOH \u2192 CH3CH2CH2OH(l) + H2(l)  (i) & (ii) are respectively dehydration and condensation type of reactions.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>1993>12>c>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS","question":"A compound contains 40.0% carbon, 6.7% hydrogen and 53.3% oxygen. Determine its molecular formula if its molar mass is 180 (H = 1, C = 12, O = 16)","images":[],"marking_scheme":"Carbon 40.O% = 40/12 = 3.33 moles ; Hydrogen 6.7% moles 6.71=6.7   moles Oxygen 53.3% = 53.3/16 = 3.33 moles    Divide through by smaller number    i.e. C 33/3.33 : H 6.7/3.33 : O 3.33/3.33    C = 1: H = 2.0: O = 1    Empirical formula = (CH2O)x = 180  i.e. (30)x = 180  x = 180/30 = 6  Molecular formula = C6H12O6","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>12>c>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS","question":"Explain why ethanoic acid boils at a much higher temperature than butane even though their molar masses almost equal.","images":[],"marking_scheme":"The intermolecular bonding in ethanoic acid is hydrogen bonding while the butane molecules are only aggregated by weak van der Waals.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>13>a>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"What is meant by the rate of a chemical reaction?","images":[],"marking_scheme":"Rate of a chemical reaction is the number of moles of reactant converted or product formed per unit time.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>13>a>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Explain in terms of the vision theory, the effect of temperature increase on reaction rate.","images":[],"marking_scheme":"Collision theory states that the reactant molecules must collide with one another before forming the product. The number of collisions is directly proportional to the rate of reaction. This value of rate of reaction is however limited by the number of molecules attaining the activation energy and having appropriate orientation of the molecules. Increase in temperature only favours endothermic process and low temperature will favour the exothermic process. Low temperature however slows the rate of reaction and therefore catalyst is applied.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>1993>13>b>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"CHEMICAL REACTIONS : CHEMICAL EQUATIONS AND IUPAC NAMES OF CHEMICAL COMPOUNDS.","question":"When hydrogen peroxide is exposed to air, it decomposes:    Write an equation for the reaction","images":[],"marking_scheme":"2H2O2(l) \u2192 2H2O(l) + O2(g)","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>1993>13>b>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"When hydrogen peroxide is exposed to air, it decomposes:  Outline an experiment to illustrate that effect of a named catalyst on the rate of decomposition.","images":[],"marking_scheme":"Thermodynamically, the decomposition of hydrogen peroxide is spontaneous. When hydrogen peroxide is put in a conical flask, nothing seem to happen. However. the addition of hydrogen peroxide to a little amount of manganese(IV) oxide (MnO2  ) generates effervescence and a gas is vigorously given off. The reaction of MnO2   on the decomposition of hydrogen peroxide is catalystic.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>1993>13>b>iii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"iii","group":"","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"When hydrogen peroxide is exposed to air, it decomposes:  Sketch an energy profile diagram to show the effect of the catalyst on the reaction rate, given that the reaction is exothermic.","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>1993>13>c","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"c","group":"","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"Explain why enthalpy data alone cannot be used to predict whether a reaction can occur spontaneously or not.","images":[],"marking_scheme":"Certain endothermic processes can be exothermic at a certain condition of temperature.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>1993>14>a>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.","question":"List four characteristic properties of transition metals","images":[],"marking_scheme":"-They have variaable oxidation state  -They have complex process of ion formation  -The two metals that can be extracted from their ore by electrolysis are coloured metallic ions.  -They can also act as catalysts","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>14>a>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS","question":"Name two metals that can be extracted from their ore by electrolysis.","images":[],"marking_scheme":"Calcium and Magnesium.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>14>b>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Determine the oxidation number of chromium in Cr2O2\u22127","images":[],"marking_scheme":"2Cr - 14 = -2;  2Cr = -2 + 14 = 12  Cr = 12/2 = 6   the oxidation number of Cr = +6","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1993>14>b>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"State the colour observed on adding a few drops of dilute tetraoxosulphate (VI) acid to the system representedby the following equation:   Cr2O2\u22127(aq) + H2O(l) \u21cc 2CrO2\u22124(aq) + 2H+(aq). Explain your answer.","images":[],"marking_scheme":"On addition of few drops of dilutes H2SO4 the equilibrium system, the solution colour changes from yellow to green because Cr+6 is reduced to Cr3+","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>1993>14>c>i","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"ACIDS, BASES AND SALTS : ACID-BASE REACTIONS","question":"State and explain what would be observed if hydrogen sulphide gas were bubbled into acidified K2Cr2O7. Write an equation for the reaction.","images":[],"marking_scheme":"The solution changes from yellow colour to green and sulphur is precipitated because H2SO4 is oxidized to elementary sulphur.  Cr2O2\u22127(aq)+3H2S(g)+8H+(aq)\u21922Cr3+(aq)+7H2Ol)+3S(s)","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>1993>14>c>ii","subject":"Chemistry","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"NON METALS AND THEIR COMPOUNDS : HYDROGEN SULPHIDE","question":"What precaution should be taken to avoid excessive exposure to hydrogen sulphide gas while it is being generated in the laboratory?","images":[],"marking_scheme":"The gas should be cautiously generated in the fume cupboard.","marks":"1","difficulty":"2"}];